                                            "display": "Ei mikään näistä",
                                            "code": "-1",
                                            "system": "https://duodecim.fi/fhir/stu3/CodeSystem/questionnaire-option-1172-live"
                                        }
                                    }
                                ]
                            },
                            {
                                "linkId": "4615",
                                "text": "<h2>Yleiset oireet</h2>"
                            },
                            {
                                "linkId": "4616",
                                "text": "Onko sinulla joku seuraavista oireista?",
