                                "text": "Oletko raskaana?"
                            },
                            {
                                "linkId": "4605",
                                "text": "Minkälaiseen vaivaan tarvitset apua?",
                                "answer": [
                                    {
                                        "valueCoding": {
                                            "id": "6155",
                                            "display": "Oikomiskojeeseen tai hammasproteesiin liittyvä oire tai ongelma",
